class RecipesForm{constructor(form){this.formName=form.attr("name");this.errors=$("#form_errors_client");this.weightsNumber=$(".recipe-weight").length-1;$("#add_recipe").on("click",this.addRecipe.bind(this));form.on("input",".recipe-name",this.recipeNameInput.bind(this));form.on("click",".recipe-result",this.recipeSearchResultClick.bind(this));form.on("click",".remove-row",this.removeRow.bind(this));form.on("submit",this.submit.bind(this))}addRecipe(event){this.weightsNumber=this.weightsNumber+1;let html="<tr><td>"+$("#"+this.formName+"_recipe_dropdown").data("prototype")+$("#"+this.formName+"_recipe_weights__name___recipe_id").data("prototype")+"</td>";html+='<td colspan="2">'+$("#"+this.formName+"_recipe_weights__name___value").data("prototype")+"</td>";html+='<td><i class="remove-row fa fa-minus"></i></td></tr>';$("#add_foodstuff_recipe_button_row").before(html);let options=$("#"+this.formName+"_recipe_weights___name__");options.val(1);$('[name="'+this.formName+"[recipe_weights][__name__][recipe_id]"+'"]').attr("name",this.formName+"[recipe_weights]["+this.weightsNumber+"][recipe_id]").removeAttr("id");$('[name="'+this.formName+"[recipe_weights][__name__][value]"+'"]').attr("name",this.formName+"[recipe_weights]["+this.weightsNumber+"][value]").removeAttr("id");event.preventDefault()}recipeNameInput(event){let thisElement=$(event.target);let row=new this.FoodRow(event.target);let valueInput=encodeURI(thisElement.val().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,""));let searchResults=row.getSearchResults();searchResults.html("");let url=$("#recipe_search").data("search").replace("__title__",valueInput);if(this.timeout){clearTimeout(this.timeout);this.timeout=null}this.timeout=setTimeout(()=>{$.ajax({url:url,type:"GET",success:data=>{if(valueInput!==""){searchResults.html(data)}else{searchResults.html("")}$(".recipe-result").each((index,element)=>{let id=$(element).attr("id").replace("recipe_result_","");let name=$(element).text().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"");if(valueInput===name){row.getRecipeId().val(id)}})},error:()=>{searchResults.html("Er ging iets fout.")}})},1e3)}recipeSearchResultClick(event){let thisElement=$(event.target);let row=new this.FoodRow(event.target);let id=thisElement.attr("id").replace("recipe_result_","");let name=thisElement.text();row.getName().val(name);row.getRecipeId().val(id)}removeRow(event){new this.FoodRow(event.target).row.remove()}submit(event){let text="";let recipeNames=[];$(".recipe-name").each((index,element)=>{if(recipeNames.includes($(element).val())){text=text+"Dubbel recept.";event.preventDefault()}recipeNames.push($(element).val())});this.errors.html(text)}FoodRow=class{constructor(thisElement){this.row=$(thisElement).closest("tr")}getRecipeId(){return this.row.find(".recipe-id")}getName(){return this.row.find(".dropdown-toggle")}getWeight(){return this.row.find(".recipe-weight")}getSearchResults(){return this.row.find(".dropdown-menu-food")}}}